-- ============================================
-- Legislacao full-site: helder-salomao / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/178873
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 113 rows Camara legacy existentes, somente 83
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=178873, tipo Deputado(a), ordemAssinatura=1.
-- 30 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'helder-salomao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'helder-salomao: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 113 THEN
    RAISE EXCEPTION 'Pre-condicao helder-salomao: esperadas 113 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2609960', '2608089', '2610302', '2610301', '2609324', '2610018', '2607055', '2609980', '2608310', '2607077', '2607076', '2607054', '2607052', '2606466', '2607051', '2606085', '2597228', '2594164', '2607049', '2604094', '2607047', '2606932', '2600102', '2591362', '2588252', '2587390', '2585800', '2585721', '2584422', '2584164', '2591516', '2591364', '2588253', '2588038', '2588257', '2588250', '2585823', '2585761', '2585720', '2588256', '2588249', '2585814', '2585726', '2588254', '2588232', '2585808', '2585723', '2585690', '2584169', '2584143', '2584134', '2585804', '2585722', '2584423', '2584168', '2584142', '2585718', '2584174', '2584157', '2584139', '2584135', '2584176', '2584163', '2584140', '2584136', '2584141', '2584128', '2584138', '2584137', '2584133', '2618205', '2616311', '2615784', '2615781', '2614242', '2607737', '2615783', '2610304', '2609416', '2607734', '2615825', '2615782', '2614961');
  IF target_present <> 83 THEN
    RAISE EXCEPTION 'Pre-condicao helder-salomao: esperadas 83 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2609960', '2608089', '2610302', '2610301', '2609324', '2610018', '2607055', '2609980', '2608310', '2607077', '2607076', '2607054', '2607052', '2606466', '2607051', '2606085', '2597228', '2594164', '2607049', '2604094', '2607047', '2606932', '2600102', '2591362', '2588252', '2587390', '2585800', '2585721', '2584422', '2584164', '2591516', '2591364', '2588253', '2588038', '2588257', '2588250', '2585823', '2585761', '2585720', '2588256', '2588249', '2585814', '2585726', '2588254', '2588232', '2585808', '2585723', '2585690', '2584169', '2584143', '2584134', '2585804', '2585722', '2584423', '2584168', '2584142', '2585718', '2584174', '2584157', '2584139', '2584135', '2584176', '2584163', '2584140', '2584136', '2584141', '2584128', '2584138', '2584137', '2584133', '2618205', '2616311', '2615784', '2615781', '2614242', '2607737', '2615783', '2610304', '2609416', '2607734', '2615825', '2615782', '2614961')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'helder-salomao-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao helder-salomao: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao helder-salomao: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

